INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00684', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「我常向植物學習，覺得他們是最能接受命運，也最不向命運屈服的。他們不會動，種子落在哪兒， 就注定一輩子，在那裡生根、成長、死亡。如果是人，遇到這樣不平的遭遇，一定會反抗。但植物 無語，他們以另一種方式發言。在熱帶莽林中，上面是遮天的濃蔭，白天黑得像夜晚一樣，許多小 樹只能長到一呎多，就再也無法發育。他們卑微地活著，直到有一天，上面的大樹因為雷雨折斷， 他們就立刻竄上去，成為大樹。在沙漠裡，白天熱得可以烤蛋，許多種子伏在炙人的砂土下，乾得 像是砂的一部分，但是只要有一陣雨，他們就快速萌發、成長、開花。」 下列敘述，符合上文旨意的選項是：', '["人會反抗，植物不會反抗", "只要努力，不可妥協，才能成功", "植物的生長，展現出「掌握時機」的智慧", "植物雖然看似脆弱，卻具有強韌的生命力 「聽天由命」和「隨波逐流」不足以說明植物長成的道理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00685', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「百年前，祖輩渡海來臺。彼時地景枯黃無綠，他們不分冬夏，將幾千幾百斤的汗水灑進地裡，但 乾渴的砂土仍張著龜裂大口張狂索求。被日光曬得刺燙燙的砂地如一塊烙鐵，驅趕著踩踏其上的農 人。但有人始終不走，他們直立旱地等待。日日夜夜，季季年年，終於等到灣寶庄農地重劃，興圳 建渠。可惜砂地如漏，水還未浸透，即迅速流逝。幸賴神明指引，庄民徒手徒腳、齊心齊力，共同 鏟挖庄內的紅色黏土丘，將其厚鋪於砂壤，仔細翻攪，此後，再灑下的幾千幾百斤汗水，才開始值 得。一直以來，灣寶的農民習於不著鞋履走入田地。早期因為窮困，如今則因田壟有水。泥糊糊， 溫潤潤，一踏進，就像裹上一層新生的肌膚。農人的掌有老繭，腰背僵硬，往往帶病在身。但他們 仍堅持走進農田，將鋤頭一次一次地劈進地裡。」 依據上文，下列敘述正確的是：', '["早期灣寶的地質惡劣，不利耕作", "灣寶農民以前習慣不穿鞋是因為生活貧困", "因為居住條件不佳，灣寶早已人去樓空，成為廢墟", "灣寶農民劈進地裡的不只是鋤頭，還有一股有志竟成的精神 灣寶土地改良的方式是將砂土與黏土和在一起，如此可避免砂壤大量流失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00686', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '「面對電腦的運算能力每兩年就會倍增的飆速發展，我們的社會結構一直處於落後科技發展的狀 態，唯一的方法就是增加社會的適應力，也就是要使學習的效益達到最佳化，並將創新特質運用到 文化與社會結構上，破除因循僵化、講求靈活應變，以縮短從錯誤學習的時間。大學課程的推陳出 新也日益加快，有些課程甚至已標上時效。而隨著創新週期愈來愈短，學習適應的時間愈來愈少， 我們所面對的穩定狀態也有了變化，只有不穩定的固定狀態以及偶爾不穩定狀態的差異，新的穩定 狀態必定是動態穩定，就像騎腳踏車一樣，必須在雙腳不停地踩動下一直前進。」 根據上文，說明正確的選項是：', '["人類社會的結構總是無法跟上電腦運算能力的迅速發展", "提高學習效益可增加社會的整體適應力，維持靜態穩定", "行政機關以穩定為要，避免因創新融入而帶來擾動不安", "為了符應社會變動的需求，大學開設時效課程將成為一種趨勢 最佳適應力表現在失敗後能快速修正，並維持動態平衡的前進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00687', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-01c5eaab', 'sub-elementary-6f0ba476-05', NULL, 'single_choice', '下列選項，適合平行機關間使用的是：', '["「檢陳」、「附送」", "「希查照」、「附送」", "「請查照」、「附送」", "「請查照」、「希查照」 「請查照」、「敬表同意」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00688', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '當民眾在申報綜合所得稅時，須額外考量納稅者權利保護法中每人基本生活費之相關規定。試問此做法 乃下列何項原則之適用？', '["新法優於舊法原則", "實質課稅原則", "實體從舊程序從新原則", "特別法優於普通法原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "9589f1a36fa0", "answer_pdf_sha1": "cdfb65d0daca", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00689', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '稅法對於怠報金一般會有最高金額的限制，其所遵循的主要租稅法原則為何？', '["比例", "實質課稅", "信賴保護", "一行為不二罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "9589f1a36fa0", "answer_pdf_sha1": "cdfb65d0daca", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00690', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，當納稅義務人故意以詐欺或其他不正當方法逃漏稅捐者，其稅捐的核課期間為幾年？', '["5年", "7年", "10年", "情節重大核課無期限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "9589f1a36fa0", "answer_pdf_sha1": "cdfb65d0daca", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00691', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，依稅法規定應自他人取得之憑證及給予他人憑證之存根或副本，應保存幾年？', '["3", "4", "5", "6"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "9589f1a36fa0", "answer_pdf_sha1": "cdfb65d0daca", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00692', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於規定地價及房屋標準價格，於評定後各應每幾年重新規定地價一次及重行評定一次？', '["2年；2年", "2年；3年", "3年；2年", "3年；3年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "9589f1a36fa0", "answer_pdf_sha1": "cdfb65d0daca", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00693', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-111-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，納稅義務人向稅捐稽徵機關申請延期或分期繳納稅額，其延期或分期繳納期間不得 逾多久？', '["6個月", "1年", "18個月", "3年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "9589f1a36fa0", "answer_pdf_sha1": "cdfb65d0daca", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
